259	/** Editable inspector for plan_view elements (Properties tab). */
260	export function InspectorPlanViewEditor({
261	  el,
262	  elementsById,
263	  revision,
264	  onPersistProperty,
265	}: {
266	  el: Extract<Element, { kind: 'plan_view' }>;
267	  elementsById: Record<string, Element>;
268	  revision: number;
269	  onPersistProperty: (key: string, value: string) => void;
