372	        onClick={onUndo}
373	        title="Undo (⌘Z)"
374	        aria-label="Undo"
375	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
376	      >
377	        <Icons.undo size={ICON_SIZE.chrome} aria-hidden="true" />
378	      </button>
379	      <span className="text-muted">{depth}</span>
380	      <button
381	        type="button"
382	        onClick={onRedo}
383	        title="Redo (⇧⌘Z)"
384	        aria-label="Redo"
385	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
386	      >
387	        <Icons.redo size={ICON_SIZE.chrome} aria-hidden="true" />
388	      </button>
389	    </div>
390	  );
391	}
392	
393	function WsCluster({ state }: { state: StatusWsState }): JSX.Element {
394	  const palette: Record<StatusWsState, { color: string; label: string }> = {
395	    connected: { color: 'var(--color-success)', label: 'connected' },
396	    reconnecting: { color: 'var(--color-warning)', label: 'reconnecting' },
397	    offline: { color: 'var(--color-danger)', label: 'offline' },
398	  };
399	  const { color, label } = palette[state];
400	  return (
401	    <div
402	      aria-live={state === 'offline' ? 'assertive' : 'polite'}
403	      title={`Connection: ${label}`}
404	      className="flex items-center gap-1"
405	    >
406	      <Icons.online size={ICON_SIZE.chrome} aria-hidden="true" style={{ color }} />
407	      <span>ws:</span>
408	      <span style={{ color }}>{label}</span>
409	    </div>
410	  );
411	}
412	
413	function SaveCluster({ state }: { state: StatusSaveState }): JSX.Element {
414	  const text: Record<StatusSaveState, string> = {
415	    saved: 'saved',
416	    saving: 'saving…',
417	    unsynced: 'unsynced',
418	    error: 'save failed',
419	  };
420	  return (
421	    <div
422	      aria-live={state === 'error' ? 'assertive' : 'polite'}
423	      title={`Save state: ${text[state]}`}
424	      className="font-medium"
425	      style={{
426	        color:
427	          state === 'error'
428	            ? 'var(--color-danger)'
429	            : state === 'unsynced'
430	              ? 'var(--color-warning)'
431	              : 'var(--color-foreground)',
432	      }}
433	    >
434	      {text[state]}
435	    </div>
436	  );
437	}
438	
439	export type { ReactNode };
440

