317	/* ────────────────────────────────────────────────────────────────────── */
318	/* Numeric expression evaluator — §13.3                                    */
319	/* ────────────────────────────────────────────────────────────────────── */
320	
321	/**
322	 * Evaluate a §13.3 numeric expression. Supports `+`, `-`, `*`, `/`,
323	 * parentheses, and decimal numbers. Returns `null` for invalid input
324	 * so callers can keep the prior value and surface an error inline.
325	 */
326	export function evaluateExpression(raw: string): number | null {
327	  const trimmed = raw.trim();
328	  if (!trimmed) return null;
329	  if (!/^[\d+\-*/().\s]+$/.test(trimmed)) return null;
330	  try {
331	    // eslint-disable-next-line @typescript-eslint/no-implied-eval
332	    const value = Function(`'use strict'; return (${trimmed});`)();
333	    return Number.isFinite(value) ? Number(value) : null;
334	  } catch {
335	    return null;
336	  }
337	}
338	
339	const UNIT_CYCLE = ['mm', 'cm', 'm'] as const;
340	export type LengthUnit = (typeof UNIT_CYCLE)[number];
341	
342	function unitToMm(value: number, unit: LengthUnit): number {
343	  if (unit === 'mm') return value;
344	  if (unit === 'cm') return value * 10;
345	  return value * 1000;
